const sourceName = 'OpenAI News';
const sourceType = 'primaire';
const category = 'ai-news';
const tags = ['ia', 'openai', 'news'];

function cleanup(value) {
  return String(value ?? '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

return $input.all().map((item) => {
  const json = item.json;
  return {
    json: {
      source_name: sourceName,
      source_type: sourceType,
      category,
      tags,
      title: cleanup(json.title || ''),
      url: json.link || json.url || '',
      published_at: json.isoDate || json.pubDate || new Date().toISOString(),
      raw_excerpt: cleanup(json.contentSnippet || json.content || json.summary || json['content:encoded'] || ''),
      source_id: json.guid || json.id || json.link || json.url || '',
    },
  };
});

const sourceName = 'Google AI Blog';
const sourceType = 'primaire';
const category = 'ai-news';
const tags = ['ia', 'google', 'gemini', 'news'];

function cleanup(value) {
  return String(value ?? '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

return $input.all().map((item) => {
  const json = item.json;
  return {
    json: {
      source_name: sourceName,
      source_type: sourceType,
      category,
      tags,
      title: cleanup(json.title || ''),
      url: json.link || json.url || '',
      published_at: json.isoDate || json.pubDate || new Date().toISOString(),
      raw_excerpt: cleanup(json.contentSnippet || json.content || json.summary || json['content:encoded'] || ''),
      source_id: json.guid || json.id || json.link || json.url || '',
    },
  };
});

const now = Date.now();
const maxAgeMs = 14 * 24 * 60 * 60 * 1000;
const prereleasePattern = /\b(alpha|beta|nightly|rc)\b/i;

function slugify(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);
}

function cleanup(value, limit = 1500) {
  return String(value ?? '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, limit);
}

const filtered = $input
  .all()
  .map((item) => item.json)
  .filter((item) => item.title && item.url)
  .filter((item) => {
    const published = Date.parse(item.published_at || '');
    if (!Number.isNaN(published) && now - published > maxAgeMs) {
      return false;
    }
    if (item.category === 'cli-release' && prereleasePattern.test(item.title)) {
      return false;
    }
    return true;
  });

const latestBySource = new Map();
for (const item of filtered) {
  const key = item.source_name || item.category || item.url;
  const current = latestBySource.get(key);
  const itemDate = Date.parse(item.published_at || '') || 0;
  const currentDate = current ? (Date.parse(current.published_at || '') || 0) : -1;
  if (!current || itemDate > currentDate) {
    latestBySource.set(key, item);
  }
}

const candidates = [...latestBySource.values()]
  .sort((a, b) => (Date.parse(b.published_at || '') || 0) - (Date.parse(a.published_at || '') || 0));

return candidates.map((item) => {
  const datePart = String(item.published_at || new Date().toISOString()).slice(0, 10);
  const sourceSlug = slugify(item.source_name);
  const titleSlug = slugify(item.title) || 'entry';
  const fileName = `${datePart}-${sourceSlug}-${titleSlug}.md`;
  const rawExcerpt = cleanup(item.raw_excerpt);
  const summaryPrompt = `Tu es un assistant de veille passive technologique. Reponds uniquement en JSON valide, sans markdown ni texte supplementaire. Utilise exactement ce schema: {\"summary_points\":[\"...\",\"...\",\"...\"],\"points_to_verify\":[\"...\",\"...\"],\"confidence\":\"high|medium|low\",\"major_update\":true}. Ecris en francais. Base-toi uniquement sur les metadonnees et l'extrait fournis. Si la source est officielle ou une release GitHub officielle, le niveau de confiance est generalement high.\n\nSource: ${item.source_name}\nType: ${item.source_type}\nCategorie: ${item.category}\nTitre: ${item.title}\nURL: ${item.url}\nPublication: ${item.published_at}\nExtrait: ${rawExcerpt}`;

  return {
    json: {
      ...item,
      raw_excerpt: rawExcerpt,
      confidence: item.source_type === 'primaire' ? 'high' : 'medium',
      fileName,
      outputPath: `/vault/raw/passive/provider-news/${fileName}`,
      summary_prompt: summaryPrompt,
    },
  };
});

return $input.all().map((item) => {
  const response = item.json || {};
  const text = response?.choices?.[0]?.message?.content || '{}';
  return { json: { text } };
});

function yamlString(value) {
  const safe = String(value ?? '')
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"');
  return `"${safe}"`;
}

function cleanup(value, limit = 1200) {
  return String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, limit);
}

function bulletize(values, fallback) {
  if (!Array.isArray(values) || values.length === 0) {
    return [`- ${fallback}`];
  }
  return values.slice(0, 5).map((value) => `- ${cleanup(value, 220)}`);
}

const collectedAt = new Date().toISOString();

return $input.all().map((item) => {
  const json = item.json;
  let parsed = {};

  try {
    parsed = JSON.parse(json.text || '{}');
  } catch (error) {
    parsed = {};
  }

  const summaryPoints = bulletize(parsed.summary_points, 'Resume IA non structure disponible, a relire manuellement.');
  const pointsToVerify = bulletize(parsed.points_to_verify, 'Confirmer les details techniques si cette entree devient une vraie note.');
  const confidence = ['high', 'medium', 'low'].includes(parsed.confidence)
    ? parsed.confidence
    : (json.confidence || 'medium');
  const majorUpdate = typeof parsed.major_update === 'boolean' ? parsed.major_update : false;
  const title = cleanup(json.title, 300);
  const excerpt = cleanup(json.raw_excerpt || 'Aucun extrait disponible.', 1500);
  const tags = Array.isArray(json.tags) ? json.tags : [];

  const markdown = `---\nkind: passive-capture\nsource_name: ${yamlString(json.source_name)}\nsource_type: ${json.source_type}\ncategory: ${json.category}\ntags: [${tags.join(', ')}]\ntitle: ${yamlString(title)}\nurl: ${yamlString(json.url)}\npublished_at: ${yamlString(json.published_at)}\ncollected_at: ${yamlString(collectedAt)}\nconfidence: ${confidence}\nmajor_update: ${majorUpdate}\nworkflow: passive-provider-news\nstatus: a-traiter\n---\n\n# ${title}\n\n## Metadonnees\n- Source : ${json.source_name}\n- Type : ${json.source_type}\n- Categorie : ${json.category}\n- URL : ${json.url}\n- Publie le : ${json.published_at}\n- Collecte le : ${collectedAt}\n- Niveau de confiance : ${confidence}\n\n## Extrait brut\n${excerpt}\n\n## Resume IA preliminaire\n${summaryPoints.join('\n')}\n\n## Points a verifier\n${pointsToVerify.join('\n')}\n\n## Action possible\n- [ ] Decider si cette entree merite une vraie note dans \`wiki/notes/\`\n`;

  return {
    json: {
      ...json,
      collected_at: collectedAt,
      confidence,
      major_update: majorUpdate,
      markdown,
    },
  };
});
